// ─── Types ──────────────────────────────────────────────────────────────────

export type RoutingStatus =
  | 'ROUTED'
  | 'COMPANY_DEPT'
  | 'COMPANY_ONLY'
  | 'UNROUTED'
  | 'SKIPPED';

export type RoutingMethod =
  | 'PO_NUMBER'
  | 'SO_NUMBER'
  | 'FUZZY_NAME'
  | 'EMAIL_DOMAIN'
  | 'SUBJECT_MATCH'
  | 'AI'
