  private deriveAttribution(
    matchedPeople: PersonWorkspaceEntity[],
  ): AttributionResult {
    const externalPeople = matchedPeople.filter(
      (p) =>
        !p.emails?.primaryEmail?.toLowerCase().endsWith(`@${INTERNAL_DOMAIN}`),
